### JavaScript: Add New Dexie.js Database for Dumping

Source: https://github.com/dexie/dexie.js/blob/master/samples/open-existing-db/dump-databases.html

This JavaScript function, `addDatabase`, allows users to manually add a database name to a list for subsequent dumping. It prompts the user for a database name, then attempts to open it using Dexie.js. If the database exists and can be opened, its name is stored in a special internal Dexie database named `__dbnames`, making it discoverable by the main dumping logic. This is useful for including databases not automatically detected by `Dexie.getDatabaseNames`.

```JavaScript
function addDatabase(ev) {
  const dbname = prompt("Enter name of a database on this origin (" + location.host + ")");
  if (!dbname) return;
  console.log("Trying to open " + dbname);
  return new Dexie(dbname, {addons: []}).open().then(function (db) {
    console.log("Database " + dbname + " found. Adding it to __dbnames db");
    db.close();
  }).then(function () {
    return new Dexie ("__dbnames", {addons: []}).open();
  }).then(function (db) {
    return db.table("dbnames").put({name: dbname}).then(function() {
      db.close();
    });
  }).then(function(){
    console.log("Succcessfully added " + dbname + ". Please reload page to dump it!");
  }).catch(function (error) {
    console.error(error);
  });
}
```

